// Bundled skills — skills that ship with the web build and are seeded into
// every chat's `.gab/skills/<name>/` folder on creation (and on load for
// existing chats). Same write-if-missing semantics as default prompts:
// existing files are left alone so user edits persist.
//
// The manifest (`bundled-skills.json`) is auto-generated by build.sh by
// scanning web/ for subdirectories that contain a SKILL.md. To add a new
// bundled skill, drop the folder into web/ and rebuild — no code changes.

export async function seedBundledSkills(vfs) {
    let manifest;
    try {
        const r = await fetch('./bundled-skills.json');
        if (!r.ok) return;
        manifest = await r.json();
    } catch {
        return;  // no manifest (e.g. served raw from web/) — silent no-op
    }

    for (const [name, files] of Object.entries(manifest)) {
        for (const file of files) {
            const target = `.gab/skills/${name}/${file}`;
            if (await vfs.fileExists(target)) continue;
            try {
                const fr = await fetch(`./${name}/${file}`);
                if (!fr.ok) continue;
                const text = await fr.text();
                await vfs.writeFile(target, text);
            } catch {
                /* skip individual fetch failures */
            }
        }
    }
}
